#include <bits/stdc++.h>
using namespace std;

const int mod=1000000007;

int T;
long long n;
int ans[2][2],base[2][2],tmp[2][2];

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%lld",&n);
        ans[0][0]=ans[1][1]=1;
        ans[0][1]=ans[1][0]=0;
        base[0][0]=0;
        base[0][1]=base[1][0]=base[1][1]=1;
        n--;
        while(n){
            if(n&1){
                for(int i=0;i<2;i++)
                    for(int j=0;j<2;j++)
                        tmp[i][j]=(1ll*ans[i][0]*base[0][j]+1ll*ans[i][1]*base[1][j])%mod;
                for(int i=0;i<2;i++)
                    for(int j=0;j<2;j++)
                        ans[i][j]=tmp[i][j];
            }
            for(int i=0;i<2;i++)
                for(int j=0;j<2;j++)
                    tmp[i][j]=(1ll*base[i][0]*base[0][j]+1ll*base[i][1]*base[1][j])%mod;
            for(int i=0;i<2;i++)
                for(int j=0;j<2;j++)
                    base[i][j]=tmp[i][j];
            n>>=1;
        }
        printf("%d\n",((long long)ans[0][1]+ans[1][0]+ans[1][1])%mod);
    }
    return 0;
}
